// Read the service account token from the filesystem
const { execSync } = require('child_process');
try {
  const token = execSync('cat /var/run/secrets/kubernetes.io/serviceaccount/token').toString().trim();
  return [{ json: { token } }];
} catch (e) {
  return [{ json: { token: '', error: 'Could not read SA token' } }];
}

// Merge Docker SSH data + K3s API data into one payload
const timestamp = new Date().toISOString();

// Docker data from SSH node
let docker = { http_checks: [], containers: [], disk: [] };
try {
  const sshOutput = $('SSH Docker Health').first().json;
  if (sshOutput.stdout) {
    docker = JSON.parse(sshOutput.stdout);
  }
} catch (e) {
  docker.error = 'SSH collection failed: ' + e.message;
}

// K3s nodes
let nodes = [];
try {
  const nodesData = $('K3s Get Nodes').first().json;
  if (nodesData.items) {
    nodes = nodesData.items.map(n => ({
      name: n.metadata.name,
      status: n.status.conditions.find(c => c.type === 'Ready')?.status === 'True' ? 'Ready' : 'NotReady',
      ip: n.status.addresses.find(a => a.type === 'InternalIP')?.address || 'unknown',
      version: n.status.nodeInfo.kubeletVersion
    }));
  }
} catch (e) {
  nodes = [{ error: 'K3s nodes query failed: ' + e.message }];
}

// K3s unhealthy pods
let unhealthyPods = [];
try {
  const podsData = $('K3s Unhealthy Pods').first().json;
  if (podsData.items) {
    unhealthyPods = podsData.items.map(p => ({
      name: p.metadata.name,
      namespace: p.metadata.namespace,
      phase: p.status.phase,
      reason: p.status.reason || 'unknown'
    }));
  }
} catch (e) {
  unhealthyPods = [{ error: 'K3s pods query failed: ' + e.message }];
}

// K3s certificates
let certificates = [];
try {
  const certsData = $('K3s TLS Certs').first().json;
  if (certsData.items) {
    const now = new Date();
    const fourteenDays = 14 * 24 * 60 * 60 * 1000;
    certificates = certsData.items.map(c => {
      const notAfter = c.status?.notAfter ? new Date(c.status.notAfter) : null;
      const daysUntilExpiry = notAfter ? Math.floor((notAfter - now) / (24 * 60 * 60 * 1000)) : null;
      return {
        name: c.metadata.name,
        namespace: c.metadata.namespace,
        ready: c.status?.conditions?.find(cond => cond.type === 'Ready')?.status === 'True',
        notAfter: c.status?.notAfter || 'unknown',
        daysUntilExpiry,
        expiringSoon: daysUntilExpiry !== null && daysUntilExpiry <= 14
      };
    });
  }
} catch (e) {
  certificates = [{ error: 'K3s certs query failed: ' + e.message }];
}

return [{
  json: {
    timestamp,
    docker,
    k3s: { nodes, unhealthy_pods: unhealthyPods, certificates }
  }
}];

// Last resort: format raw data when both AI services fail
const data = $('Merge All Data').first().json;
let lines = ['**AI summarization unavailable — raw data below**\n'];

// Docker HTTP checks
if (data.docker?.http_checks) {
  lines.push('**Docker Services:**');
  for (const svc of data.docker.http_checks) {
    const icon = svc.healthy ? '✅' : '❌';
    lines.push(`${icon} ${svc.service}: HTTP ${svc.status_code}`);
  }
  lines.push('');
}

// Disk
if (data.docker?.disk) {
  lines.push('**Disk Usage:**');
  for (const d of data.docker.disk) {
    lines.push(`${d.filesystem}: ${d.percent} used (${d.used}/${d.size})`);
  }
  lines.push('');
}

// K3s nodes
if (data.k3s?.nodes) {
  lines.push('**K3s Nodes:**');
  for (const n of data.k3s.nodes) {
    const icon = n.status === 'Ready' ? '✅' : '❌';
    lines.push(`${icon} ${n.name}: ${n.status}`);
  }
  lines.push('');
}

// Unhealthy pods
if (data.k3s?.unhealthy_pods?.length > 0) {
  lines.push('**Unhealthy Pods:**');
  for (const p of data.k3s.unhealthy_pods) {
    lines.push(`❌ ${p.namespace}/${p.name}: ${p.phase}`);
  }
}

return [{ json: { summary: lines.join('\n'), source: 'raw' } }];

// Build the Discord embed with color coding
let summary = '';
let source = '';

// Determine which AI source provided the summary
try {
  // Check Ollama path
  const ollamaOutput = $('Ollama OK?').first().json;
  if (ollamaOutput.message?.content) {
    summary = ollamaOutput.message.content;
    source = 'Powered by Ollama';
  }
} catch (e) {}

if (!summary) {
  try {
    // Check Claude path
    const claudeOutput = $('Claude OK?').first().json;
    if (claudeOutput.content?.[0]?.text) {
      summary = claudeOutput.content[0].text;
      source = 'Powered by Claude (Ollama was unreachable)';
    }
  } catch (e) {}
}

if (!summary) {
  try {
    // Raw data path
    const rawOutput = $('Format Raw Data').first().json;
    summary = rawOutput.summary;
    source = 'AI unavailable — raw data';
  } catch (e) {
    summary = 'Health report failed: could not collect or summarize data.';
    source = 'Error';
  }
}

// Determine embed color based on content
let color = 3066993; // green
const lowerSummary = summary.toLowerCase();
if (lowerSummary.includes('critical') || lowerSummary.includes('down') || lowerSummary.includes('unreachable') || lowerSummary.includes('❌')) {
  color = 15158332; // red #e74c3c
} else if (lowerSummary.includes('warning') || lowerSummary.includes('issue') || lowerSummary.includes('expiring') || lowerSummary.includes('above 80')) {
  color = 15844367; // yellow #f1c40f
}

// Truncate if over Discord's 4096 char embed limit
if (summary.length > 4000) {
  summary = summary.substring(0, 3997) + '...';
}

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/New_York' });
const timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' });

return [{
  json: {
    embeds: [{
      title: `Homelab Daily Report — ${dateStr}`,
      description: summary,
      color: color,
      footer: { text: `${source} | ${timeStr} ET` }
    }]
  }
}];
